import React from 'react'

import Dep from './Dep/Dep'

import './Depoimentos.css'

export default () => {

    // Seleciona todos os botões de rádio
    var radios = document.querySelectorAll('.slide-controller input[type=radio]');

    // Adiciona um ouvinte de evento 'change' a cada botão de rádio
    for (var i = 0; i < radios.length; i++) {
        radios[i].addEventListener('change', function () {
            // Atualiza a variável CSS '--selected-item' com o índice do botão de rádio selecionado
            document.documentElement.style.setProperty('--selected-item', this.value);
        });
    }

    return (
        <section id="depoimentos">

            <div id='depTitle'>
                <h3>Reconhecimento</h3>
            </div>


            <div className='slide-show' >

                <div className="slider-list">

                    <Dep img={""} name={"Matheus Ximenes"} cargo={"Presidente Empresa X"}
                        dep={"Desta maneira, a revolução dos costumes estende o alcance e a importância dos conhecimentos estratégicos para atingir a excelência."}
                    ></Dep>


                    <Dep img={""} name={"Gustavo Souza"} cargo={"Diretor Empresa Y"}
                        dep={"Todas estas questões, devidamente ponderadas, levantam dúvidas sobre se a contínua expansão de nossa atividade pode nos levar a considerar a reestruturação do levantamento das variáveis envolvidas."}
                    ></Dep>
                </div>

            </div>

            <div className="slide-controller">
                <input type="radio" name="slide" checked="checked" />
                <input type="radio" name="slide" />
                <input type="radio" name="slide" />
                <input type="radio" name="slide" />
            </div>



        </section >
    )
}
